<template>
  <div>
    <h1 style="margin-bottom: 0;">{{ data.contestantName }}</h1>
    <p style="margin-bottom: 0; font-size: 18px; color: #888">{{ data.description }}</p><br/>
    <h2>评分项目</h2>
    <a-card style="width: 100%; margin-bottom: 20px; border-radius: 8px;" v-for="(item, index) in data.scoreRecords" :key="index">
      <div style="display: flex; width: 100%">
        <div style="flex: 1">
          <h2>{{ item.ruleName }}（{{ item.ruleMinScore }}-{{ item.ruleMaxScore }}分）</h2>
          <span>{{ item.description }}</span>
          <h2>您的打分：
            <a-input-number disabled v-model="item.score" style="margin: 0 10px; height: 40px; padding-top: 4px; width: 120px;"></a-input-number>分
          </h2>
        </div>
      </div>
    </a-card>
  </div>
</template>
<script>
import { getJudgeScoreDetail } from '@/api/judge'
export default {
  data() {
    return {
      data: {
        contestantName: '',
      },
    }
  },
  mounted() {
    getJudgeScoreDetail(this.$route.params.cid, this.$route.params.voteId).then(res => {
      this.data = res
    })
  },
}
</script>
